INSERT INTO core_team (name, role, type, quote, bio, research, display_order, image_url) VALUES 
('DR. RAVISHANKAR P DESAI', 'FACULTY MENTOR', 'faculty', 'Guiding the next generation of innovators.', 'Dr. Desai is a distinguished professor with over 15 years of experience in robotics research. He provides invaluable guidance and mentorship to the club members.', 'Control Systems, AI/ML & RL for Autonomous Robot, Control of Autonomous (Marine, Aerial, and Ground) Vehicles, Process and Biomedical Instrumentation, Underwater and Medical Image Processing', 1, '/media/desai.png'),
('SHASHWAT MISHRA', 'PRESIDENT', 'member', 'Innovation distinguishes between a leader and a follower.', 'Shashwat is a visionary leader with a passion for robotics and AI. He has led multiple successful projects and is dedicated to fostering a culture of innovation within the club.', 'Autonomous Navigation, Defence Robotics, Artificial Intelligence in Robotics.', 2, '/media/Shashwat.jpg'),
('YASHASHWINI RAO', 'STUDENT MENTOR', 'member', 'Empowering others to achieve their best.', 'Yashashwini is an experienced senior member who loves teaching and mentoring juniors. She specializes in embedded systems and circuit design.', 'Embedded Systems, IoT, Signal Processing.', 3, '/media/Yashashwini.jpeg'),
('C RITHVIK BHASKAR', 'STUDENT MENTOR', 'member', 'Sharing knowledge is the key to growth.', 'AI-focused technologist passionate about impactful innovation. Combines leadership with strong execution to deliver real-world solutions. Driven to inspire teams and shape a smarter future.', 'Artificial Intelligence, Product-Focused ML, Real-World Deployment, Innovation. FORGE → Focus, Optimize, Research, Grow, Execute', 4, '/media/Rithvik.jpeg'),
('AREKATLA NISHANTH', 'VICE PRESIDENT', 'member', 'Execution is everything.', 'Nishanth is known for his execution skills and operational excellence. He ensures that all club activities run smoothly and efficiently.', 'Mechanical Design, Kinematics, Rapid Prototyping.', 5, '/media/Nishanth.jpeg'),
('SHAIK THASLIM', 'TREASURER', 'member', 'Managing resources for maximum impact.', 'Shaik Thaslim, an Artificial Intelligence student with experience in analytical thinking and problem-solving. As Treasurer, she ensures efficient management of resources while supporting technically driven initiatives within the club.', 'Applied AI, Intelligent Systems, Data-Driven Problem Solving.', 6, '/media/Thaslim.jpg'),
('CHARITHA SREE', 'GENERAL SECRETARY', 'member', 'Building impactful tech solutions and pushing technical limits.', 'I’m Charitha Sree, a Computer Science student passionate about building impactful tech solutions. I work on full-stack development, AI-powered platforms, and competitive programming projects. I enjoy learning deeply, solving real-world problems, and constantly pushing my technical limits.', 'Full-stack Development, AI Platforms, Competitive Programming.', 7, '/media/Charitha.jpeg');
